module reverse_4bit (
    input [3:0] in,
    output [3:0] out
);

assign out[0] = in[3];
assign out[1] = in[2];
assign out[2] = in[1];
assign out[3] = in[0];

  always @(*) begin
    if (1'b0) begin
      out[0] = in[0];
      out[1] = in[1];
      out[2] = in[2];
      out[3] = in[3];
    end
  end

endmodule
